const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
tasksRoutes = require('./modules/tasks/routes');
commentsRoutes = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);

module.exports = app;

const sendError = (res, status, code, message) => {
  res.status(status).json({ error: { code, message } });
};

module.exports = { sendError };

const { randomUUID } = require('node:crypto');

const generateId = () => {
  return randomUUID();
};

module.exports = { generateId };

const express = require('express');
const commentsService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router({ mergeParams: true });

router.post('/', async (req, res) => {
  const { message } = req.body;
  if (!message) {
    return sendError(res, 400, 'INVALID_INPUT', 'Message is required');
  }

  const comment = await commentsService.createComment(req.params.projectId, req.params.taskId, message);
  if (!comment) {
    return sendError(res, 404, 'PROJECT_OR_TASK_NOT_FOUND', 'Project or task not found');
  }

  res.status(201).json({ comment });
});

module.exports = router;

const { generateId } = require('../../lib/id');
let projectsStore = {};

const createComment = (projectId, taskId, message) => {
  if (!projectsStore[projectId] || !projectsStore[projectId].tasks[taskId]) {
    return null;
  }

  const commentId = generateId();
  const comment = { id: commentId, message };

  projectsStore[projectId].tasks[taskId].comments.push(comment);
  return comment;
};

module.exports = { createComment };

const express = require('express');
const membersService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router({ mergeParams: true });

router.post('/', async (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_INPUT', 'UserId and role are required');
  }

  const member = await membersService.addMember(req.params.projectId, userId, role);
  if (!member) {
    return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  }

  res.status(201).json({ member });
});

module.exports = router;

const { generateId } = require('../../lib/id');
let projectsStore = {};

const addMember = (projectId, userId, role) => {
  if (!projectsStore[projectId]) {
    return null;
  }

  const member = { id: generateId(), userId, role };
  projectsStore[projectId].members.push(member);
  return member;
};

module.exports = { addMember };

const express = require('express');
const projectsService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'INVALID_INPUT', 'Name is required');
  }

  const project = await projectsService.createProject(name);
  res.status(201).json({ project });
});

router.get('/', async (req, res) => {
  const projects = await projectsService.getAllProjects();
  res.json({ projects });
});

module.exports = router;

const { generateId } = require('../../lib/id');
let projectsStore = {};

const createProject = (name) => {
  const projectId = generateId();
  const project = { id: projectId, name, members: [], tasks: {} };
  projectsStore[projectId] = project;
  return project;
};

const getAllProjects = () => {
  return Object.values(projectsStore);
};

module.exports = { createProject, getAllProjects };

const express = require('express');
tasksService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router({ mergeParams: true });

router.post('/', async (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'INVALID_INPUT', 'Name is required');
  }

  const task = await tasksService.createTask(req.params.projectId, name);
  if (!task) {
    return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  }

  res.status(201).json({ task });
});

router.get('/', async (req, res) => {
  const tasks = await tasksService.getAllTasks(req.params.projectId);
  if (!tasks) {
    return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  }

  res.json({ tasks });
});

router.patch('/:taskId', async (req, res) => {
  const { status } = req.body;
  if (!status || !['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_INPUT', 'Status must be either todo or done');
  }

  const task = await tasksService.updateTask(req.params.projectId, req.params.taskId, status);
  if (!task) {
    return sendError(res, 404, 'PROJECT_OR_TASK_NOT_FOUND', 'Project or task not found');
  }

  res.json({ task });
});

module.exports = router;

const { generateId } = require('../../lib/id');
let projectsStore = {};

const createTask = (projectId, name) => {
  if (!projectsStore[projectId]) {
    return null;
  }

  const taskId = generateId();
  const task = { id: taskId, name, status: 'todo', comments: [] };
  projectsStore[projectId].tasks[taskId] = task;
  return task;
};

const getAllTasks = (projectId) => {
  if (!projectsStore[projectId]) {
    return null;
  }

  const tasks = Object.values(projectsStore[projectId].tasks);
  return tasks;
};

const updateTask = (projectId, taskId, status) => {
  if (!projectsStore[projectId] || !projectsStore[projectId].tasks[taskId]) {
    return null;
  }

  const task = projectsStore[projectId].tasks[taskId];
  task.status = status;
  return task;
};

module.exports = { createTask, getAllTasks, updateTask };
